import java.io.*;import java.util.*;class Main{static int check(String s){int n=s.length();boolean lo=false,up=false,dig=false;for(char c:s.toCharArray()){lo|=Character.isLowerCase(c);up|=Character.isUpperCase(c);dig|=Character.isDigit(c);}int missing=(lo?0:1)+(up?0:1)+(dig?0:1);ArrayList<Integer>runs=new ArrayList<>();for(int i=0;i<n;){int j=i;while(j<n&&s.charAt(j)==s.charAt(i))j++;if(j-i>=3)runs.add(j-i);i=j;}if(n<6)return Math.max(missing,6-n);int rep=0;for(int r:runs)rep+=r/3;if(n<=20)return Math.max(missing,rep);int del=n-20,rem=del;runs.sort(Comparator.comparingInt(a->a%3));for(int i=0;i<runs.size()&&rem>0;i++){int r=runs.get(i),use=Math.min(rem,r%3+1);runs.set(i,r-use);rem-=use;}for(int i=0;i<runs.size()&&rem>0;i++){int r=runs.get(i),use=Math.min(rem,Math.max(0,r-2));runs.set(i,r-use);rem-=use;}rep=0;for(int r:runs)rep+=Math.max(0,r)/3;return del+Math.max(missing,rep);}public static void main(String[]args)throws Exception{String[]d=new String(System.in.readAllBytes()).trim().split("\\s+");if(d.length==1&&d[0].isEmpty())return;int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){if(tc>0)out.append("\n\n");out.append(check(d[idx++]));}System.out.print(out);}}
